import{_ as l,o as r,c as a,ae as e}from"./chunks/framework.DrYEjkpc.js";const k=JSON.parse('{"title":"SkillNet","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillnet.md","filePath":"radar/tech-skillnet.md"}'),o={name:"radar/tech-skillnet.md"};function i(n,t,s,h,d,g){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="skillnet" tabindex="-1">SkillNet <a class="header-anchor" href="#skillnet" aria-label="Permalink to &quot;SkillNet&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 召回 / Skill 评测 / Skill 管理 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.65</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 把 <strong>200K+ Skill 生态</strong>组织成「应用商店基础设施」—— Ontology 三层架构 + 5 维质量评分（GitHub 735 ★）。</p><p><strong>来源</strong>:</p><ul><li>学术 + 公开服务 - 浙大 NLP（KG 实验室）</li><li>论文 + 开源 + 在线知识库</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">arXiv 2603.04448</a></li><li>GitHub：<a href="https://github.com/zjunlp/SkillNet" target="_blank" rel="noreferrer">zjunlp/SkillNet</a></li><li>在线知识库：<a href="http://skillnet.openkg.cn/" target="_blank" rel="noreferrer">skillnet.openkg.cn</a></li><li>HuggingFace 博客：<a href="https://huggingface.co/blog/xzwnlp/skillnet" target="_blank" rel="noreferrer">xzwnlp/skillnet</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h3><p>把&quot;Skill 生态&quot;从无组织的 <strong>200K+ 个孤岛</strong>升级为可治理的知识图谱：</p><ol><li><strong>Skill Ontology 三层架构</strong> — 领域分类（如&quot;数据处理&quot;&quot;代码生成&quot;）→ Skill 实体（200K+）→ 关系图谱（功能重叠 / 依赖 / 升级版）。</li><li><strong>5 维质量评分</strong> — 安全 / 完整 / 可执行 / 可维护 / 成本，超越 Star 数。</li><li><strong>实证验证</strong> — ALFWorld / WebShop / ScienceWorld 三环境 <strong>+40% reward、-30% 执行步骤</strong>。</li></ol><h3 id="核心创新" tabindex="-1">核心创新 <a class="header-anchor" href="#核心创新" aria-label="Permalink to &quot;核心创新&quot;">​</a></h3><ul><li>业界首个面向 Skill 生态的关系治理框架（而非孤立条目）</li><li>把&quot;Skill 内在质量&quot;标准化（从此可超越社区下载量做评价）</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>Skill 自动分类、查重、关系建模</li><li>多维质量评分</li><li>在线开放知识库</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>5 维评分评估的是 <strong>&quot;Skill 写得好不好&quot;</strong>，不是 <strong>&quot;在你的场景有没有效&quot;</strong>（这是两个不同问题）</li><li>团队自述：&quot;动态组合和跨领域迁移仍具挑战性&quot;</li><li>关系图谱能识别重叠但<strong>不执行自动合并</strong></li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.70</td><td>论文 + 开源 + 在线服务三栖</td></tr><tr><td>创新性</td><td>0.70</td><td>Ontology + 5 维评分是开创性贡献</td></tr><tr><td>落地程度</td><td>0.55</td><td>公共知识库，企业私有部署较少</td></tr><tr><td>生态活跃度</td><td>0.65</td><td>持续更新</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.65</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">SkillNet 论文</a></li><li><a href="https://github.com/zjunlp/SkillNet" target="_blank" rel="noreferrer">GitHub</a></li><li><a href="https://huggingface.co/blog/xzwnlp/skillnet" target="_blank" rel="noreferrer">HuggingFace 博客</a></li></ul>',29)])])}const c=l(o,[["render",i]]);export{k as __pageData,c as default};
